import{_ as s,M as o,p as d,q as l,R as e,N as i,V as n,t,a1 as c}from"./framework-5866ffd3.js";const u={},p=e("h1",{id:"litigation-ontology",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#litigation-ontology","aria-hidden":"true"},"#"),t(" Litigation Ontology")],-1),g={style:{"margin-top":"-0.5em"}},h=e("em",null,"by Nathan Dahlberg • last updated Mar 30, 2023",-1),f=e("h2",{id:"overview-labels-entities-and-events",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#overview-labels-entities-and-events","aria-hidden":"true"},"#"),t(" Overview: Labels, entities, and events")],-1),m=c('<p><strong>Classification Labels</strong>: Labels are classification tags applied to a single docket entry. As seen below the set of labels is extensive and includes many fine-grained and overlapping distinctions. Importantly the models that identify these labels do so from the text of an individual docket entry, no additional information about the case or other entries plays a role in which labels are assigned to an entry.</p><p><strong>Named Entities</strong>: Named-entities include specific information that has been extracted from the text. These include things like party names, filing dates, and many more nuanced features described below. Like classification labels, entities are extracted from the text of a single entry and lack awareness of the rest of the case.</p><p><strong>Pathway Events</strong>: Pathway events are a special kind of label that may be assigned to a docket entry and which can be used to give a rough overview of the case&#39;s litigation pathway. Each docket entry can have at most a single pathway event and currently there are only two types of events: case openings and dispositive events. Pathway events are assigned to docket entries using all of the possible information available, including all labels, entities, and metadata associated with a case.</p><h2 id="pathway-events" tabindex="-1"><a class="header-anchor" href="#pathway-events" aria-hidden="true">#</a> Pathway Events</h2><h3 id="case-openings" tabindex="-1"><a class="header-anchor" href="#case-openings" aria-hidden="true">#</a> Case Openings</h3><p>We identify the following opening events on the docket. Only the first appearance of any of the following events is deemed the case <em>opening</em> and will appear as an <code>entry.event</code>, however subsequent appearances of these events can be identified using the <code>entry.labels</code> object.</p><p><strong>Complaint:</strong> An initial pleading filed by a plaintiff that outlines the claims against a defendant, setting the foundation for a civil lawsuit.</p><p><strong>Inbound Transfer:</strong> An indication that the case has been transferred in from another another court, typically due to a change in jurisdiction or venue. This can initiate a new docket in the receiving court.</p><p><strong>Indictment:</strong> A formal charge issued by a grand jury, accusing an individual or entity of committing a crime, initiating a criminal prosecution.</p><p><strong>Information:</strong> A formal criminal charge, similar to an indictment, but filed by a prosecutor instead of a grand jury, initiating a criminal case.</p><p><strong>Notice of Removal:</strong> A document filed by a defendant to transfer a case from state court to federal court, typically due to federal jurisdiction or diversity of citizenship between parties.</p><p><strong>Petition:</strong> A formal written request submitted to a court, asking for a specific action or order, often used to initiate certain types of legal proceedings.</p><h3 id="dispositive-events" tabindex="-1"><a class="header-anchor" href="#dispositive-events" aria-hidden="true">#</a> Dispositive Events</h3><p>Dispositive events include both events that resolve the case in its entirety and those which dispose of a party or claim. Because these include partial resolutions, multiple dispositive events can be identified in a single docket.</p><p><strong>Administrative Closing:</strong> A procedural action taken by the court to temporarily remove a case from its active docket, usually pending the resolution of a related matter or awaiting further developments.</p><p><strong>Case Dismissed:</strong> Entries that clearly dismiss the case but do not fall into any of the other dispositive event categories are tagged with this label.</p><p><strong>Consent Decree:</strong> A court-approved agreement between parties to resolve a dispute, often involving the settlement of a lawsuit without an admission of guilt or liability by the defendant.</p><p><strong>Default Judgment:</strong> A ruling in favor of the plaintiff when the defendant fails to respond or appear in court, resulting in an automatic decision without a full trial.</p><p><strong>Outbound Transfer:</strong> An event where a case is transferred from one court to another, typically due to a change in jurisdiction or venue, and is removed from the transferring court&#39;s docket.</p><p><strong>Party Resolution:</strong> The settlement of a legal dispute between parties outside of court, often through negotiation or alternative dispute resolution methods, such as mediation or arbitration.</p><p><strong>Remand:</strong> A court order sending a case back to a lower court for further action or reconsideration, often due to procedural errors or new evidence.</p><p><strong>Rule 12b:</strong> A motion to dismiss a case for specific reasons outlined in the Federal Rules of Civil Procedure, such as lack of jurisdiction, improper venue, or failure to state a claim upon which relief can be granted. Actions on motions to dismiss that partially dismiss the case, including some of the claims or parties, are included.</p><p><strong>Rule 68:</strong> A procedure under the Federal Rules of Civil Procedure that allows a defendant to make a formal settlement offer to the plaintiff, potentially shifting the costs of litigation if the plaintiff ultimately recovers less than the offer amount.</p><p><strong>Summary Judgment:</strong> A court ruling that decides a case without a full trial when there are no genuine disputes over material facts and the moving party is entitled to judgment as a matter of law. Actions on motions for summary judgment that partially dismiss the case, including some of the claims or parties, are included.</p><p><strong>Trial:</strong> A formal legal proceeding where parties present evidence and arguments to a judge or jury to determine the outcome of a case, either in a criminal prosecution or a civil lawsuit.</p><h2 id="classifier-labels" tabindex="-1"><a class="header-anchor" href="#classifier-labels" aria-hidden="true">#</a> Classifier Labels</h2><h3 id="attributes" tabindex="-1"><a class="header-anchor" href="#attributes" aria-hidden="true">#</a> Attributes</h3><p><strong>Bilateral:</strong> A mutual agreement or action involving two parties or sides.</p><p><strong>Case Opened in Error:</strong> A situation where a case is mistakenly filed or initiated in the court system.</p><p><strong>Dismiss Without Prejudice:</strong> A court order that allows a case to be refiled at a later date, as the dismissal does not constitute a final judgment on the merits.</p><p><strong>Dismiss With Prejudice:</strong> A court order that permanently dismisses a case, preventing the plaintiff from refiling the same claim in the future.</p><p><strong>Error:</strong> A mistake or inaccuracy, typically found in court documents or proceedings.</p><p><strong>Proposed:</strong> A suggested or submitted document or action, usually pending court review or approval.</p><p><strong>Unopposed:</strong> A document, motion, or action that has not been contested or challenged by the opposing party.</p><h3 id="entry-types" tabindex="-1"><a class="header-anchor" href="#entry-types" aria-hidden="true">#</a> Entry Types</h3><p><strong>Answer:</strong> A defendant&#39;s formal response to a plaintiff&#39;s claims, addressing and contesting the allegations in a complaint.</p><p><strong>Arrest:</strong> The act of detaining a person suspected of committing a crime by law enforcement officers.</p><p><strong>Brief:</strong> A written document submitted by a party in a legal proceeding, outlining the facts, legal arguments, and precedents supporting their position.</p><p><strong>Complaint:</strong> An initial pleading filed by a plaintiff that outlines the claims against a defendant, setting the foundation for a civil lawsuit.</p><p><strong>Consent Decree:</strong> A court-approved agreement between parties to resolve a dispute, often involving the settlement of a lawsuit without an admission of guilt or liability by the defendant.</p><p><strong>Consent Judgment:</strong> A judgment issued by a court based on an agreement between the parties involved in a lawsuit, typically resolving the dispute without a trial.</p><p><strong>Findings of Fact:</strong> A court&#39;s written determination of the facts relevant to a case, usually based on evidence presented during a trial or hearing.</p><p><strong>Indictment:</strong> A formal charge issued by a grand jury, accusing an individual or entity of committing a crime, initiating a criminal prosecution.</p><p><strong>Information:</strong> A formal criminal charge, similar to an indictment, but filed by a prosecutor instead of a grand jury, initiating a criminal case.</p><p><strong>Judgment:</strong> A court&#39;s final decision on the legal issues and claims presented in a case, often involving the award of damages or other remedies.</p><p><strong>Minute Entry:</strong> A brief summary or notation of the events that occurred during a court proceeding, typically recorded by the court clerk.</p><p><strong>Motion:</strong> A formal request submitted to the court by a party in a legal proceeding, asking for a specific action, ruling, or order.</p><p><strong>Notice:</strong> A written document informing a party of a legal proceeding, action, or requirement, often used to provide formal notification of deadlines or court dates.</p><p><strong>Order:</strong> A written directive issued by a court or judge, instructing parties to perform certain actions or abide by specific guidelines.</p><p><strong>Petition:</strong> A formal written request submitted to a court, asking for a specific action or order, often used to initiate certain types of legal proceedings.</p><p><strong>Plea Agreement:</strong> A negotiated agreement between a defendant and a prosecutor in a criminal case, in which the defendant typically pleads guilty to a lesser charge in exchange for a reduced sentence or other concessions.</p><p><strong>Response:</strong> A party&#39;s written reply to a document or motion filed by another party in a legal proceeding, addressing the arguments or requests raised.</p><p><strong>Settlement Agreement:</strong> A legally binding contract between parties involved in a dispute, outlining the terms and conditions of a mutually agreed-upon resolution.</p><p><strong>Stipulation:</strong> A formal agreement between parties in a legal proceeding, establishing facts or terms to be accepted as true or binding.</p><p><strong>Summons:</strong> A legal document issued by a court, informing a person that they are required to appear in court or respond to a legal action</p><p><strong>Summons:</strong> A legal document issued by a court or other authority, requiring an individual or entity to appear in court or respond to a lawsuit.</p><p><strong>Transfer:</strong> A procedural action where a case is moved from one court to another, typically due to a change in jurisdiction or venue.</p><p><strong>Trial:</strong> A formal legal proceeding where parties present evidence and arguments to a judge or jury to determine the outcome of a case, either in a criminal prosecution or a civil lawsuit.</p><p><strong>Verdict:</strong> The final decision made by a judge or jury in a court case, determining the outcome and resolving the issues at hand.</p><p><strong>Waiver:</strong> A voluntary relinquishment of a legal right, claim, or privilege, often used to expedite legal proceedings or simplify procedural matters.</p><p><strong>Warrant:</strong> A legal document issued by a judge or other judicial authority, authorizing law enforcement to perform specific actions, such as conducting a search or making an arrest.</p><h3 id="court-actions" tabindex="-1"><a class="header-anchor" href="#court-actions" aria-hidden="true">#</a> Court Actions</h3><p><strong>Case Dismissed:</strong> The termination of a legal proceeding without a final determination on the merits, either due to procedural issues or the plaintiff&#39;s failure to prove their case.</p><p><strong>Consent Decree Resolution:</strong> A court-approved agreement between parties to resolve a dispute, often involving the settlement of a lawsuit without an admission of guilt or liability by the defendant.</p><p><strong>Default Judgment Resolution:</strong> A ruling in favor of the plaintiff when the defendant fails to respond or appear in court, resulting in an automatic decision without a full trial.</p><p><strong>Granting Motion for Summary Judgment:</strong> A court ruling that decides a case without a full trial when there are no genuine disputes over material facts and the moving party is entitled to judgment as a matter of law.</p><p><strong>Granting Motion to Dismiss:</strong> A court order terminating a legal proceeding due to specific reasons, such as lack of jurisdiction, improper venue, or failure to state a claim upon which relief can be granted.</p><p><strong>Remand Resolution:</strong> A court order sending a case back to a lower court for further action or reconsideration, often due to procedural errors or new evidence.</p><p><strong>Rule 68 Resolution:</strong> A settlement procedure under the Federal Rules of Civil Procedure that allows a defendant to make a formal settlement offer to the plaintiff, potentially shifting the costs of litigation if the plaintiff ultimately recovers less than the offer amount.</p><p><strong>Sentence:</strong> The final judgment of punishment imposed by a court in a criminal case, determining the consequences for the convicted individual.</p><h3 id="motion-types" tabindex="-1"><a class="header-anchor" href="#motion-types" aria-hidden="true">#</a> Motion Types</h3><p><strong>Dismissing Motion:</strong> A court order denying a motion or request made by a party in a legal proceeding, typically due to a lack of merit or procedural defects.</p><p><strong>Motion for Default Judgment:</strong> A request made by a plaintiff for a judgment in their favor due to the defendant&#39;s failure to respond or appear in court.</p><p><strong>Motion for Habeas Corpus:</strong> A legal action requesting that a person being held in custody be brought before the court to determine the legality of their detention.</p><p><strong>Motion for Judgment:</strong> A request made by a party in a legal proceeding for a court to issue a final decision on a specific issue or the entire case.</p><p><strong>Motion for Judgment as a Matter of Law:</strong> A request made by a party during a trial for the court to decide in their favor based on the evidence presented, arguing that no reasonable jury could reach a different conclusion.</p><p><strong>Motion for Judgment on the Pleadings:</strong> A request made by a party for a court to decide a case based solely on the pleadings filed, without considering additional evidence.</p><p><strong>Motion for Settlement:</strong> A request made by a party in a legal proceeding for the court to approve a negotiated resolution of the dispute between the parties.</p><p><strong>Motion for Summary Judgment:</strong> A request made by a party in a legal proceeding for the court to decide a case without a full trial when there are no genuine disputes over material facts and the moving party is entitled</p><p><strong>Motion for Summary Judgment:</strong> A motion requesting the court to rule on a case without a full trial, arguing that there are no genuine disputes over material facts and the moving party is entitled to judgment as a matter of law.</p><p><strong>Motion for Time Extension:</strong> A motion asking the court to extend a deadline or time limit for a specific action, often due to unforeseen circumstances or the need for additional preparation.</p><p><strong>Motion to Certify Class:</strong> A motion filed by the plaintiff in a class action lawsuit, seeking the court&#39;s approval to proceed as a representative of a group of similarly situated individuals or entities.</p><p><strong>Motion to Dismiss:</strong> A motion requesting the court to terminate a legal proceeding, typically due to procedural issues, lack of jurisdiction, or failure to state a claim upon which relief can be granted.</p><p><strong>Motion to Remand:</strong> A motion asking the court to send a case back to a lower court for further action or reconsideration, often due to procedural errors or new evidence.</p><p><strong>Motion to Seal:</strong> A motion requesting the court to protect sensitive or confidential information in a case by restricting public access to specific documents or portions of the court record.</p><h3 id="notice-types" tabindex="-1"><a class="header-anchor" href="#notice-types" aria-hidden="true">#</a> Notice Types</h3><p><strong>Notice of Appeal:</strong> A formal notification filed by a party to inform the court and other parties of their intention to appeal a decision or judgment to a higher court.</p><p><strong>Notice of Consent:</strong> A document filed by parties in a lawsuit indicating their agreement to have a specific issue or the entire case decided by a magistrate judge, rather than a district judge.</p><p><strong>Notice of Dismissal</strong>: A document filed by a party, usually the plaintiff, informing the court of their intention to voluntarily dismiss a case or specific claims within a case.</p><p><strong>Notice of Motion:</strong> A document filed by a party to notify the court and other parties of their intention to seek a specific court order or ruling, usually accompanied by the motion and supporting documents.</p><p><strong>Notice of Removal:</strong> A document filed by a defendant to transfer a case from state court to federal court, typically due to federal jurisdiction or diversity of citizenship between parties.</p><p><strong>Notice of Settlement:</strong> A document filed by parties in a lawsuit to inform the court that they have reached a settlement or resolution, often leading to the dismissal of the case.</p><p><strong>Notice of Voluntary Dismissal:</strong> A document filed by the plaintiff to voluntarily dismiss their case or specific claims, usually due to a settlement or resolution outside of court.</p><h3 id="petition-types" tabindex="-1"><a class="header-anchor" href="#petition-types" aria-hidden="true">#</a> Petition Types</h3><p><strong>Petition for Habeas Corpus:</strong> A legal action challenging the legality of a person&#39;s detention or imprisonment, seeking a court order for their release if the detention is deemed unlawful.</p><h3 id="stipulation-types" tabindex="-1"><a class="header-anchor" href="#stipulation-types" aria-hidden="true">#</a> Stipulation Types</h3><p><strong>Stipulation for Judgment:</strong> A written agreement between parties in a lawsuit, outlining the terms of a judgment that both parties have agreed upon, typically to resolve a dispute without further litigation.</p><p><strong>Stipulation for Settlement:</strong> A written agreement between parties in a lawsuit, outlining the terms of a settlement to resolve their dispute, usually leading to the dismissal of the case.</p><p><strong>Stipulation of Dismissal:</strong> A written agreement between parties in a lawsuit to dismiss the case or specific claims, typically as a result of a settlement or resolution outside of court.</p><h3 id="trial-types" tabindex="-1"><a class="header-anchor" href="#trial-types" aria-hidden="true">#</a> Trial Types</h3><p><strong>Bench Trial:</strong> A trial where the judge, rather than a jury, hears the evidence and arguments presented by the parties and decides the outcome of the case.</p><p><strong>Jury Trial:</strong> A trial where a jury of citizens, selected by the parties, hears the evidence and arguments presented and decides the outcome of the case, under the supervision of a judge.</p><h3 id="waiver-types" tabindex="-1"><a class="header-anchor" href="#waiver-types" aria-hidden="true">#</a> Waiver Types</h3><p><strong>Waiver of Indictment:</strong> A voluntary agreement by a defendant to waive their right to have a grand jury review the criminal charges against them, allowing the case to proceed directly to trial or plea negotiations based on an information filed by the prosecutor.</p><h2 id="named-entities" tabindex="-1"><a class="header-anchor" href="#named-entities" aria-hidden="true">#</a> Named Entities</h2><p>SCALES NER ontology coming soon.</p>',106);function y(b,v){const a=o("font"),r=o("RouterLink");return d(),l("div",null,[p,e("div",g,[i(a,{size:"2"},{default:n(()=>[h]),_:1})]),f,e("p",null,[t("The SCALES Litigation Ontology is a curated collection of features that can be extracted from docket sheets using the "),i(r,{to:"/nlp/"},{default:n(()=>[t("SCALES NLP")]),_:1}),t(" Python module. The creation of this ontology is the product of a collaborative effort between legal scholars, practitioners, and knowledge workers to identify the most significant information that can be extracted to facilitate legal research. The features that our tools extract are organized into three categories:")]),m])}const A=s(u,[["render",y],["__file","index.html.vue"]]);export{A as default};
